 10	import { toolsByName, tools, type Tool } from "./tools.ts";   // tools.ts 记得 export toolsByName
 11	import { confirm } from "./utils.js";
 12	import readline from "node:readline";
 13	import { join } from "node:path";
 14	
 15	import { Compile } from "typebox/compile";
 16	import { Value } from "typebox/value";
 17	
 18	import { createOpenAiApi } from "./providers/openai.ts"
 19	import { createAnthropicApi } from "./providers/anthropic.ts"
 20	import type { Api, Message } from "./providers/types.ts"
 21	import type { TSchema,Static } from "typebox";
 22	
 23	import { SessionStorage } from "./session/storage.ts";
 24	import { buildContext } from "./session/build.ts";
 25	import { mkdir } from "node:fs/promises";
 26	
 27	
 28	function createApi(): Api {
 29	    let api: Api;
 30	    const provider = process.env.PROVIDER || "anthropic"
 31	    if (provider === "anthropic" ){
 32	    api = createAnthropicApi({
 33	            name: "anthropic",
 34	            apiKey: process.env.ANTHROPIC_API_KEY ?? "",
 35	            baseURL: "https://api.anthropic.com",
 36	            version: "2023-06-01",
 37	            max_tokens: 4096,
 38	        })
 39	    } else if (provider === "openai"){
 40	        api = createOpenAiApi({
 41	            name: "openai",
 42	            baseURL: "https://api.openai.com",
 43	            apiKey: process.env.OPENAI_API_KEY ?? "",
 44	        })
 45	    } else {
 46	        // openai 兼容的格式
 47	        api = createOpenAiApi({
 48	            name: process.env.PROVIDER || "openai",
 49	            baseURL: process.env.DEEPSEEK_BASE_URL || "https://api.openai.com",
 50	            apiKey: process.env.DEEPSEEK_API_KEY ?? "", 
 51	        })
 52	    }
 53	    return api
 54	}
 55	    
 56	const validatorCache = new WeakMap();
 57	
 58	function validateArgs(tool: Tool<TSchema>, rawArgs: Record<string, unknown>) {
 59	    const args = structuredClone(rawArgs);
 60	    Value.Convert(tool.parameters, args);
 61	    let v = validatorCache.get(tool.parameters);
 62	    if (!v) { v = Compile(tool.parameters); validatorCache.set(tool.parameters, v); }
 63	    if (v.Check(args)) return { ok: true, args };
 64	    const errs = v.Errors(args).map(e => `  - ${e.instancePath || "root"}: ${e.message}`).join("\n");
 65	    return { ok: false, msg: `Validation failed:\n${errs}` };
 66	}
 67	
 68	async function beforeToolCall(name: string, args:Record<string, unknown>, rl: readline.Interface) {
 69	    if (name === "bash")       return await confirm(rl, `run: ${args.command}?`);
 70	    if (name === "write_file") return await confirm(rl, `write ${args.path}?`);
 71	    if (name === "edit_file")  return await confirm(rl, `edit ${args.path}?`);
 72	    return true;  // read_file / get_current_time 免确认
 73	}
 74	
 75	
 76	async function executeTool(name: string, args: Record<string, unknown>, signal: AbortSignal) {
 77	    const tool = toolsByName[name];
 78	    if (!tool) return `ERROR: unknown tool: ${name}`;
 79	    try {
 80	        const v = validateArgs(tool, args);
 81	        if (!v.ok) return `ERROR: ${v.msg}`;
 82	        return await tool.execute(v.args as never, { signal });
 83	        // return await tool.execute(args, { signal });
 84	    } catch (e) {
 85	        return `ERROR: ${e.message}`;
 86	    }
 87	}
 88	
 89	async function callLLM(messages: Message[], signal?: AbortSignal){
 90	    const api = createApi()
 91	    const response = await api.complete({
 92	        model: process.env.MODEL || "deepseek-v4-flash",
 93	        messages,
 94	        tools: tools,
 95	        signal: signal,
 96	    })
 97	    return response.message
 98	}
 99	
100	async function appendMessage(storage: SessionStorage, message: Message): Promise<void> {
101	    await storage.appendEntry({
102	        type: "message",
103	        id: crypto.randomUUID(),
104	        timestamp: Date.now().toString(),
105	        message
106	    })
107	}
108	
109	let currentTurnAbort: AbortController | null = null;   // module-level：当前 turn 的 controller
110	
111	async function runAgent(storage: SessionStorage, rl: readline.Interface) {
112	    // turn 级 AbortController：Ctrl+C 只中止本轮
113	    const ac = new AbortController();
114	    currentTurnAbort = ac;
115	    try {
116	        while (true) {
117	            if (ac.signal.aborted) {
118	                console.log("[turn aborted]\n");
119	                return;
120	            }
121	            const messages = await buildContext(storage.getEntries());
122	            const assistantMsg: Message = await callLLM(messages, ac.signal);
123	            await appendMessage(storage, assistantMsg);
124	            // messages.push(assistantMsg);
125	            const toolCalls = assistantMsg.toolCalls || [];
126	            if (toolCalls.length === 0) {
127	                console.log(`Assistant: ${assistantMsg.content}\n`);
128	                return;
129	            }
130	            for (const tc of toolCalls) {
131	                const args = tc.arguments;
132	                const ok = await beforeToolCall(tc.name, args, rl);
133	                if (!ok) {
134	                    await appendMessage(storage, { role: "tool", toolCallId: tc.id, content: "ERROR: user denied" });
135	                    continue;
136	                }
137	                const toolResult = await executeTool(tc.name, args, ac.signal);
138	                console.log(`▸ ${tc.name}(${tc.arguments}) → ${toolResult}`);
139	                await appendMessage(storage, {
140	                    role: "tool",
141	                    toolCallId: tc.id,
142	                    content: toolResult ?? "",
143	                });
144	            }
145	        }
146	    } finally {
147	        // process.off("SIGINT", onSigint);
148	        currentTurnAbort = null;
149	    }
150	}
151	
152	function printResumeHint(id: string, isNew: boolean): void {
153	    console.log(`${isNew ? "New" : "Resumed"} session: ${id}`);
154	    console.log(`Resume with: npx tsx agent.ts --resume ${id}`);
155	}
156	
157	async function createSession() {
158	    const resumeId = process.argv[2] === "--resume" ? process.argv[3] : undefined;
159	    const sessionDir = join(process.cwd(), "sessions");
160	    await mkdir(sessionDir, { recursive: true });
161	    const sessionId = resumeId ?? crypto.randomUUID();
162	    const filePath = join(sessionDir, `${sessionId}.jsonl`);
163	    
164	    if (resumeId) {
165	        const storage = await SessionStorage.open(filePath);
166	        printResumeHint(sessionId, false);
167	        return storage;
168	    }
169	    const storage = await SessionStorage.create(filePath, { cwd: process.cwd() });
170	    await storage.appendEntry({
171	        type: "message",
172	        id: crypto.randomUUID(),
173	        timestamp: new Date().toISOString(),
174	        message: {
175	            role: "system",
176	            content: "You are a helpful assistant. Use the provided tools when you need to look up information, run commands, or read/write files. Otherwise respond directly.",
177	        },
178	    });
179	    printResumeHint(sessionId, true);
180	    return storage;
181	}
182	
183	async function main() {
184	    const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
185	    const storage = await createSession();
186	    let lastSigintAt = 0;
187	    rl.on("SIGINT", () => {
188	        const now = Date.now();
189	        if (currentTurnAbort) {
190	            if (now - lastSigintAt < 1000) {
191	                console.log("\n[SIGINT x2] force exit");
192	                printResumeHint(storage.getMetadata().id, false);
193	                process.exit(138);  // 138 = SIGINT exit status
194	            }
195	            lastSigintAt = now;
196	            console.log("\n[SIGINT] aborting current turn...(Ctrl+C again to force exit)");
197	            currentTurnAbort.abort();
198	        } else {
199	            console.log("exit\n");
200	            printResumeHint(storage.getMetadata().id, false);
201	            rl.close();
202	            process.exit(0);
203	        }
204	    });
205	    while (true) {
206	        // const line = await new Promise((r) => rl.question("User: ", r));
207	        const line = await new Promise<string>((r) => rl.question("User: ", r));
208	        if (!line || line === "exit") break;
209	        await appendMessage(storage, {
210	            role: "user",
211	            content: line.trim(),
212	        });
213	        await runAgent(storage, rl);
214	    }
215	    rl.close();
216	}
217	
218	main();
